'use client';

import { useEffect, useState } from 'react';
import { usePathname, useRouter } from 'next/navigation';
import Link from 'next/link';
import {
  ShieldAlert, LayoutDashboard, Building2, Users, Database, Activity, LogOut, Loader2
} from 'lucide-react';

const ADMIN_TOKEN_KEY = 'zerocold_token';

const NAV_ITEMS = [
  { href: '/zerocold', label: 'لوحة التحكم', icon: LayoutDashboard },
  { href: '/zerocold/companies', label: 'الشركات', icon: Building2 },
  { href: '/zerocold/users', label: 'المستخدمين', icon: Users },
  { href: '/zerocold/database', label: 'قاعدة البيانات', icon: Database },
  { href: '/zerocold/logs', label: 'سجل الأحداث', icon: Activity },
];

export default function ZerocoldLayout({ children }: { children: React.ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const [checking, setChecking] = useState(true);
  const [authenticated, setAuthenticated] = useState(false);

  useEffect(() => {
    const checkAuth = async () => {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      if (!token) {
        setAuthenticated(false);
        setChecking(false);
        if (!pathname.startsWith('/zerocold/login') &&
            !pathname.startsWith('/zerocold/verify-telegram') &&
            !pathname.startsWith('/zerocold/verify-master')) {
          router.replace('/zerocold/login');
          return;
        }
        return;
      }

      try {
        const res = await fetch('/api/admin/session', {
          headers: { Authorization: `Bearer ${token}` },
        });

        if (res.ok) {
          const body = await res.json();
          if (body.success) {
            setAuthenticated(true);
          } else {
            localStorage.removeItem(ADMIN_TOKEN_KEY);
            if (!pathname.startsWith('/zerocold/login') &&
                !pathname.startsWith('/zerocold/verify-telegram') &&
                !pathname.startsWith('/zerocold/verify-master')) {
              router.replace('/zerocold/login');
            }
          }
        } else {
          localStorage.removeItem(ADMIN_TOKEN_KEY);
          if (!pathname.startsWith('/zerocold/login') &&
              !pathname.startsWith('/zerocold/verify-telegram') &&
              !pathname.startsWith('/zerocold/verify-master')) {
            router.replace('/zerocold/login');
          }
        }
      } catch {
        if (!pathname.startsWith('/zerocold/login') &&
            !pathname.startsWith('/zerocold/verify-telegram') &&
            !pathname.startsWith('/zerocold/verify-master')) {
          router.replace('/zerocold/login');
        }
      } finally {
        setChecking(false);
      }
    };

    checkAuth();
  }, [pathname, router]);

  const handleLogout = () => {
    localStorage.removeItem(ADMIN_TOKEN_KEY);
    router.replace('/zerocold/login');
  };

  const isAuthPage =
    pathname.startsWith('/zerocold/login') ||
    pathname.startsWith('/zerocold/verify-telegram') ||
    pathname.startsWith('/zerocold/verify-master');

  if (isAuthPage) {
    return <>{children}</>;
  }

  if (checking) {
    return (
      <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center">
        <Loader2 size={32} className="text-amber-500 animate-spin" />
      </div>
    );
  }

  if (!authenticated) {
    return null;
  }

  return (
    <div className="min-h-screen bg-[#0a0a0f] flex flex-col">
      <header className="sticky top-0 z-40 bg-[#0a0a0f]/90 backdrop-blur-md border-b border-[#1f1725]">
        <div className="max-w-6xl mx-auto px-4 h-12 flex items-center justify-between">
          <Link href="/zerocold" className="flex items-center gap-2">
            <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-amber-600 to-orange-700 flex items-center justify-center">
              <ShieldAlert className="w-3.5 h-3.5 text-white" />
            </div>
            <span className="text-sm font-bold text-amber-50">لوحة المطور</span>
          </Link>

          <nav className="hidden md:flex items-center gap-1">
            {NAV_ITEMS.map((item) => {
              const isActive = item.href === '/zerocold'
                ? pathname === '/zerocold'
                : pathname.startsWith(item.href);
              return (
                <Link
                  key={item.href}
                  href={item.href}
                  className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
                    isActive
                      ? 'bg-amber-600/15 text-amber-400 border border-amber-700/30'
                      : 'text-amber-400/50 hover:text-amber-300 hover:bg-[#12101a]'
                  }`}
                >
                  <item.icon size={14} />
                  {item.label}
                </Link>
              );
            })}
          </nav>

          <button
            onClick={handleLogout}
            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs text-red-400/60 hover:text-red-400 hover:bg-red-950/20 transition-all"
          >
            <LogOut size={14} />
            <span className="hidden sm:inline">تسجيل الخروج</span>
          </button>
        </div>

        <nav className="md:hidden flex items-center gap-1 px-4 pb-2 overflow-x-auto">
          {NAV_ITEMS.map((item) => {
            const isActive = item.href === '/zerocold'
              ? pathname === '/zerocold'
              : pathname.startsWith(item.href);
            return (
              <Link
                key={item.href}
                href={item.href}
                className={`flex-shrink-0 flex items-center gap-1 px-2.5 py-1 rounded-lg text-[0.65rem] font-medium transition-all ${
                  isActive
                    ? 'bg-amber-600/15 text-amber-400 border border-amber-700/30'
                    : 'text-amber-400/50 hover:text-amber-300 hover:bg-[#12101a]'
                }`}
              >
                <item.icon size={12} />
                {item.label}
              </Link>
            );
          })}
        </nav>
      </header>

      <main className="flex-1 page-enter">
        {children}
      </main>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import {
  Building2, Users, Database, Package, Key,
  Activity, LogOut, Clock, Server,
  HardDrive, ShieldAlert, RefreshCw, Loader2, ChevronLeft
} from 'lucide-react';
import Link from 'next/link';

const ADMIN_TOKEN_KEY = 'zerocold_token';

interface DashboardData {
  companiesCount: number;
  usersCount: number;
  dbSize: string;
  lastLogin: string;
  recentActivity: { action: string; details: string; timestamp: string }[];
  systemHealth: { apiResponseTime: string; uptime: string; dbStatus: string };
}

export default function ZerocoldDashboardPage() {
  const router = useRouter();
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchDashboard = async () => {
    setLoading(true);
    setError('');
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      if (!token) {
        router.replace('/zerocold/login');
        return;
      }

      const res = await fetch('/api/admin/dashboard', {
        headers: { Authorization: `Bearer ${token}` },
      });

      if (res.status === 401) {
        localStorage.removeItem(ADMIN_TOKEN_KEY);
        router.replace('/zerocold/login');
        return;
      }

      const body = await res.json();
      if (!body.success) {
        setError(body.message || 'حدث خطأ');
        return;
      }

      setData(body.data);
    } catch {
      setError('حدث خطأ في الاتصال بالخادم');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDashboard();
  }, []);

  const handleLogout = () => {
    localStorage.removeItem(ADMIN_TOKEN_KEY);
    router.replace('/zerocold/login');
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center">
        <Loader2 size={32} className="text-amber-500 animate-spin" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center">
        <div className="text-center">
          <ShieldAlert className="w-12 h-12 text-red-500 mx-auto mb-3" />
          <p className="text-red-400 text-sm">{error}</p>
          <button onClick={fetchDashboard} className="mt-4 text-amber-500 hover:text-amber-400 text-sm underline">
            إعادة المحاولة
          </button>
        </div>
      </div>
    );
  }

  const stats = [
    { label: 'عدد الشركات', value: data?.companiesCount ?? 0, icon: Building2, color: 'from-sky-600 to-blue-700' },
    { label: 'عدد المستخدمين', value: data?.usersCount ?? 0, icon: Users, color: 'from-emerald-600 to-green-700' },
    { label: 'حجم قاعدة البيانات', value: data?.dbSize ?? '--', icon: HardDrive, color: 'from-violet-600 to-purple-700' },
    { label: 'آخر تسجيل دخول', value: data?.lastLogin ?? '--', icon: Clock, color: 'from-amber-600 to-orange-700' },
  ];

  const quickActions = [
    { label: 'إدارة الشركات', href: '/zerocold/companies', icon: Building2, color: 'border-sky-700/30 hover:border-sky-600/50' },
    { label: 'إدارة المستخدمين', href: '/zerocold/users', icon: Users, color: 'border-emerald-700/30 hover:border-emerald-600/50' },
    { label: 'خطط الاشتراك', href: '/zerocold/plans', icon: Package, color: 'border-amber-700/30 hover:border-amber-600/50' },
    { label: 'الاشتراكات', href: '/zerocold/subscriptions', icon: Users, color: 'border-purple-700/30 hover:border-purple-600/50' },
    { label: 'أكواد التفعيل', href: '/zerocold/codes', icon: Key, color: 'border-green-700/30 hover:border-green-600/50' },
    { label: 'قاعدة البيانات', href: '/zerocold/database', icon: Database, color: 'border-violet-700/30 hover:border-violet-600/50' },
    { label: 'سجل الأحداث', href: '/zerocold/logs', icon: Activity, color: 'border-amber-700/30 hover:border-amber-600/50' },
  ];

  const healthItems = data?.systemHealth ? [
    { label: 'حالة قاعدة البيانات', value: data.systemHealth.dbStatus, color: 'text-emerald-400' },
    { label: 'زمن استجابة API', value: data.systemHealth.apiResponseTime, color: 'text-amber-400' },
    { label: 'مدة التشغيل', value: data.systemHealth.uptime, color: 'text-sky-400' },
  ] : [];

  return (
    <div className="min-h-screen bg-[#0a0a0f]">
      <div className="max-w-6xl mx-auto px-4 py-6">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-amber-600 to-orange-700 flex items-center justify-center shadow-lg shadow-amber-900/20">
              <ShieldAlert className="w-5 h-5 text-white" />
            </div>
            <div>
              <h1 className="text-lg font-bold text-amber-50">لوحة المطور</h1>
              <p className="text-[0.7rem] text-amber-400/50">نظرة عامة على النظام</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button
              onClick={fetchDashboard}
              className="p-2 rounded-xl bg-[#12101a] border border-[#2a1f0a] text-amber-500/70 hover:text-amber-400 hover:border-amber-700/50 transition-all"
              title="تحديث"
            >
              <RefreshCw size={16} />
            </button>
            <button
              onClick={handleLogout}
              className="flex items-center gap-1.5 px-3 py-2 rounded-xl bg-[#12101a] border border-[#2a1f0a] text-red-400/70 hover:text-red-400 hover:border-red-800/50 transition-all text-xs"
            >
              <LogOut size={14} />
              تسجيل الخروج
            </button>
          </div>
        </div>

        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-6">
          {stats.map((stat) => (
            <div key={stat.label} className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-4 hover:border-[#3a2f1a] transition-all">
              <div className="flex items-center justify-between mb-3">
                <span className="text-[0.7rem] text-amber-400/60 font-medium">{stat.label}</span>
                <div className={`w-8 h-8 rounded-lg bg-gradient-to-br ${stat.color} flex items-center justify-center`}>
                  <stat.icon size={14} className="text-white" />
                </div>
              </div>
              <p className="text-xl font-bold text-amber-50 font-mono">{stat.value}</p>
            </div>
          ))}
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-5">
            <h2 className="text-sm font-bold text-amber-300/80 mb-3">الوصول السريع</h2>
            <div className="grid grid-cols-2 gap-3">
              {quickActions.map((action) => (
                <Link
                  key={action.label}
                  href={action.href}
                  className={`flex items-center gap-3 p-3 rounded-xl bg-[#1a1625] border ${action.color} transition-all group`}
                >
                  <div className="w-9 h-9 rounded-lg bg-[#12101a] border border-[#2a1f0a] flex items-center justify-center group-hover:border-amber-700/50 transition-all">
                    <action.icon size={16} className="text-amber-500/70 group-hover:text-amber-400 transition-all" />
                  </div>
                  <span className="text-xs text-amber-300/70 group-hover:text-amber-200 transition-all">{action.label}</span>
                  <ChevronLeft size={14} className="mr-auto text-amber-600/30 group-hover:text-amber-500/50 transition-all" />
                </Link>
              ))}
            </div>
          </div>

          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-5">
            <h2 className="text-sm font-bold text-amber-300/80 mb-3">حالة النظام</h2>
            <div className="space-y-3">
              {healthItems.length > 0 ? healthItems.map((item) => (
                <div key={item.label} className="flex items-center justify-between p-2.5 rounded-lg bg-[#1a1625] border border-[#2a1f0a]">
                  <div className="flex items-center gap-2">
                    <Server size={14} className="text-amber-600/50" />
                    <span className="text-xs text-amber-400/60">{item.label}</span>
                  </div>
                  <span className={`text-xs font-medium ${item.color}`}>{item.value}</span>
                </div>
              )) : (
                <div className="flex items-center justify-center py-6">
                  <Activity size={20} className="text-amber-600/30" />
                  <span className="text-xs text-amber-600/40 mr-2">بيانات غير متوفرة</span>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-5">
          <h2 className="text-sm font-bold text-amber-300/80 mb-3">آخر النشاطات</h2>
          {data?.recentActivity && data.recentActivity.length > 0 ? (
            <div className="space-y-1">
              {data.recentActivity.map((activity, i) => (
                <div key={i} className="flex items-center justify-between p-2.5 rounded-lg hover:bg-[#1a1625] transition-all">
                  <div className="flex items-center gap-2.5 min-w-0">
                    <div className="w-1.5 h-1.5 rounded-full bg-amber-600/50 flex-shrink-0" />
                    <div className="min-w-0">
                      <p className="text-xs text-amber-300/80 truncate">{activity.action}</p>
                      {activity.details && (
                        <p className="text-[0.7rem] text-amber-600/50 truncate">{activity.details}</p>
                      )}
                    </div>
                  </div>
                  <span className="text-[0.65rem] text-amber-600/40 flex-shrink-0">{activity.timestamp}</span>
                </div>
              ))}
            </div>
          ) : (
            <div className="flex items-center justify-center py-6">
              <Activity size={20} className="text-amber-600/30" />
              <span className="text-xs text-amber-600/40 mr-2">لا توجد نشاطات حديثة</span>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, FormEvent } from 'react';
import { useRouter } from 'next/navigation';
import { Eye, EyeOff, Loader2, ShieldAlert } from 'lucide-react';

const ADMIN_SESSION_KEY = 'zerocold_session';

export default function ZerocoldLoginPage() {
  const router = useRouter();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setError('');

    if (!email.trim()) {
      setError('يرجى إدخال البريد الإلكتروني');
      return;
    }
    if (!password) {
      setError('يرجى إدخال كلمة المرور');
      return;
    }

    setLoading(true);
    try {
      const res = await fetch('/api/admin/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: email.trim(), password }),
      });

      const body = await res.json();

      if (!res.ok || !body.success) {
        setError(body.message || 'البريد الإلكتروني أو كلمة المرور غير صحيحة');
        return;
      }

      sessionStorage.setItem(ADMIN_SESSION_KEY, JSON.stringify({ email: email.trim(), step: 'login' }));
      router.push('/zerocold/verify-telegram');
    } catch {
      setError('حدث خطأ في الاتصال بالخادم');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-[#0a0a0f] to-[#1a0f0a] p-4">
      <div className="w-full max-w-sm">
        <div className="text-center mb-8">
          <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-amber-600 to-orange-700 flex items-center justify-center mx-auto mb-4 shadow-lg shadow-amber-900/30">
            <ShieldAlert className="w-8 h-8 text-white" />
          </div>
          <h1 className="text-2xl font-bold text-amber-50">لوحة المطور</h1>
          <p className="text-amber-400/70 text-sm mt-1">لوحة تحكم المطور الخاصة بالنظام</p>
        </div>

        <div className="bg-[#12101a] border border-[#2a1f0a] rounded-2xl p-6 shadow-2xl">
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-amber-300/80 mb-1.5">البريد الإلكتروني</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="admin@example.com"
                className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 placeholder-amber-700/50 focus:outline-none focus:border-amber-600 focus:ring-1 focus:ring-amber-600/30 transition-all text-sm"
                dir="ltr"
                autoFocus
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-amber-300/80 mb-1.5">كلمة المرور</label>
              <div className="relative">
                <input
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 placeholder-amber-700/50 focus:outline-none focus:border-amber-600 focus:ring-1 focus:ring-amber-600/30 transition-all text-sm pl-10"
                  dir="ltr"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute left-3 top-1/2 -translate-y-1/2 text-amber-600/60 hover:text-amber-400 transition-colors"
                >
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>

            {error && (
              <div className="bg-red-950/40 border border-red-800/40 text-red-400 text-sm rounded-xl px-4 py-2.5 text-center">
                {error}
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full py-2.5 bg-gradient-to-l from-amber-600 to-orange-700 hover:from-amber-500 hover:to-orange-600 disabled:from-amber-800 disabled:to-orange-900 disabled:cursor-not-allowed text-white font-semibold rounded-xl transition-all text-sm shadow-lg shadow-amber-900/20 flex items-center justify-center gap-2"
            >
              {loading && <Loader2 size={18} className="animate-spin" />}
              {loading ? 'جاري تسجيل الدخول...' : 'تسجيل الدخول'}
            </button>
          </form>
        </div>

        <p className="text-center mt-6 text-[0.7rem] text-amber-700/40">
          منطقة المطور — الدخول مقصور على المصرح لهم فقط
        </p>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, FormEvent } from 'react';
import { useRouter } from 'next/navigation';
import { Eye, EyeOff, Loader2, KeyRound, ArrowLeft, Lock } from 'lucide-react';

const ADMIN_SESSION_KEY = 'zerocold_session';
const ADMIN_TOKEN_KEY = 'zerocold_token';
const MAX_ATTEMPTS = 3;
const BLOCK_DURATION = 15 * 60 * 1000;

export default function VerifyMasterPage() {
  const router = useRouter();
  const [masterPassword, setMasterPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [attempts, setAttempts] = useState(0);
  const [blockedUntil, setBlockedUntil] = useState<number | null>(null);

  useEffect(() => {
    const session = sessionStorage.getItem(ADMIN_SESSION_KEY);
    if (!session) {
      router.replace('/zerocold/login');
      return;
    }
    try {
      const data = JSON.parse(session);
      if (data.step !== 'telegram' || !data.telegramVerified) {
        router.replace('/zerocold/login');
      }
    } catch {
      router.replace('/zerocold/login');
    }
  }, [router]);

  useEffect(() => {
    const blocked = localStorage.getItem('zerocold_master_blocked');
    if (blocked) {
      const until = parseInt(blocked, 10);
      if (Date.now() < until) {
        setBlockedUntil(until);
      } else {
        localStorage.removeItem('zerocold_master_blocked');
      }
    }
    const savedAttempts = localStorage.getItem('zerocold_master_attempts');
    if (savedAttempts) {
      setAttempts(parseInt(savedAttempts, 10));
    }
  }, []);

  useEffect(() => {
    if (blockedUntil && Date.now() >= blockedUntil) {
      setBlockedUntil(null);
      setAttempts(0);
      localStorage.removeItem('zerocold_master_blocked');
      localStorage.removeItem('zerocold_master_attempts');
    }
  }, [blockedUntil]);

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setError('');

    if (blockedUntil && Date.now() < blockedUntil) {
      const remaining = Math.ceil((blockedUntil - Date.now()) / 60000);
      setError(`تم حظر المحاولة. يرجى الانتظار ${remaining} دقائق`);
      return;
    }

    if (!masterPassword) {
      setError('يرجى إدخال كلمة السر الرئيسية');
      return;
    }

    setLoading(true);
    try {
      const session = sessionStorage.getItem(ADMIN_SESSION_KEY);
      if (!session) {
        router.replace('/zerocold/login');
        return;
      }
      const { email } = JSON.parse(session);

      const res = await fetch('/api/admin/verify-master', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, masterPassword }),
      });

      const body = await res.json();

      if (!res.ok || !body.success) {
        const apiMsg = body?.message || '';
        if (apiMsg.includes('صلاحية') || apiMsg.includes('جلس')) {
          setError(apiMsg);
          localStorage.removeItem('zerocold_master_attempts');
          return;
        }
        if (apiMsg.includes('تيليجرام')) {
          setError(apiMsg);
          return;
        }
        if (apiMsg.includes('غير صحيحة') || apiMsg.includes('غير صحيح')) {
          const newAttempts = attempts + 1;
          setAttempts(newAttempts);
          localStorage.setItem('zerocold_master_attempts', String(newAttempts));
          if (newAttempts >= MAX_ATTEMPTS) {
            const until = Date.now() + BLOCK_DURATION;
            setBlockedUntil(until);
            localStorage.setItem('zerocold_master_blocked', String(until));
            setError(`تم الحظر لمدة 15 دقيقة`);
          } else {
            setError(`المحاولات المتبقية: ${MAX_ATTEMPTS - newAttempts}`);
          }
        } else {
          setError(apiMsg || 'حدث خطأ');
        }

        setMasterPassword('');
        return;
      }

      localStorage.removeItem('zerocold_master_attempts');
      localStorage.removeItem('zerocold_master_blocked');

      const { token } = body.data;
      localStorage.setItem(ADMIN_TOKEN_KEY, token);
      sessionStorage.removeItem(ADMIN_SESSION_KEY);

      router.push('/zerocold/');
    } catch {
      setError('حدث خطأ في الاتصال بالخادم');
    } finally {
      setLoading(false);
    }
  };

  const handleBack = () => {
    sessionStorage.removeItem(ADMIN_SESSION_KEY);
    router.push('/zerocold/login');
  };

  const formatBlockTime = () => {
    if (!blockedUntil) return '';
    const remaining = Math.max(0, blockedUntil - Date.now());
    const mins = Math.ceil(remaining / 60000);
    if (mins >= 60) {
      return `${Math.floor(mins / 60)} ساعة و ${mins % 60} دقيقة`;
    }
    return `${mins} دقائق`;
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-[#0a0a0f] to-[#1a0f0a] p-4">
      <div className="w-full max-w-sm">
        <button
          onClick={handleBack}
          className="flex items-center gap-1.5 text-amber-600/60 hover:text-amber-400 text-sm mb-6 transition-colors"
        >
          <ArrowLeft size={16} />
          العودة لتسجيل الدخول
        </button>

        <div className="text-center mb-8">
          <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-red-600 to-rose-700 flex items-center justify-center mx-auto mb-4 shadow-lg shadow-red-900/30">
            <KeyRound className="w-8 h-8 text-white" />
          </div>
          <h1 className="text-2xl font-bold text-amber-50">كلمة السر الرئيسية</h1>
          <p className="text-amber-400/60 text-sm mt-2 leading-relaxed max-w-xs mx-auto">
            أدخل كلمة السر الرئيسية للوحة المطور
          </p>
        </div>

        <div className="bg-[#12101a] border border-[#2a1f0a] rounded-2xl p-6 shadow-2xl">
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-amber-300/80 mb-1.5">كلمة السر الرئيسية</label>
              <div className="relative">
                <input
                  type={showPassword ? 'text' : 'password'}
                  value={masterPassword}
                  onChange={(e) => setMasterPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 placeholder-amber-700/50 focus:outline-none focus:border-amber-600 focus:ring-1 focus:ring-amber-600/30 transition-all text-sm pl-10"
                  dir="ltr"
                  autoFocus
                  disabled={!!(blockedUntil && Date.now() < blockedUntil)}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute left-3 top-1/2 -translate-y-1/2 text-amber-600/60 hover:text-amber-400 transition-colors"
                >
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>

            {error && (
              <div className="bg-red-950/40 border border-red-800/40 text-red-400 text-sm rounded-xl px-4 py-2.5 text-center">
                {error}
              </div>
            )}

            {blockedUntil && Date.now() < blockedUntil && (
              <div className="bg-red-950/40 border border-red-800/40 text-red-400 text-sm rounded-xl px-4 py-2.5 text-center">
                <Lock size={16} className="inline ml-1.5" />
                تم الحظر. المتبقي: {formatBlockTime()}
              </div>
            )}

            <button
              type="submit"
              disabled={loading || (!!(blockedUntil && Date.now() < blockedUntil))}
              className="w-full py-2.5 bg-gradient-to-l from-red-600 to-rose-700 hover:from-red-500 hover:to-rose-600 disabled:from-red-800 disabled:to-rose-900 disabled:cursor-not-allowed text-white font-semibold rounded-xl transition-all text-sm shadow-lg shadow-red-900/20 flex items-center justify-center gap-2"
            >
              {loading ? (
                <Loader2 size={18} className="animate-spin" />
              ) : (
                <Lock size={18} />
              )}
              {loading ? 'جاري التحقق...' : 'تأكيد'}
            </button>
          </form>

          {attempts > 0 && attempts < MAX_ATTEMPTS && (
            <p className="text-amber-600/50 text-xs text-center mt-3">
              المحاولات الفاشلة: {attempts} / {MAX_ATTEMPTS}
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useRef, useEffect, KeyboardEvent, ClipboardEvent } from 'react';
import { useRouter } from 'next/navigation';
import { Loader2, MessageCircle, ArrowLeft } from 'lucide-react';

const ADMIN_SESSION_KEY = 'zerocold_session';
const RESEND_COOLDOWN = 60;

export default function VerifyTelegramPage() {
  const router = useRouter();
  const [code, setCode] = useState<string[]>(Array(6).fill(''));
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [countdown, setCountdown] = useState(RESEND_COOLDOWN);
  const [canResend, setCanResend] = useState(false);
  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);

  useEffect(() => {
    const session = sessionStorage.getItem(ADMIN_SESSION_KEY);
    if (!session) {
      router.replace('/zerocold/login');
      return;
    }
    try {
      const data = JSON.parse(session);
      if (data.step !== 'login') {
        router.replace('/zerocold/login');
      }
    } catch {
      router.replace('/zerocold/login');
    }
  }, [router]);

  useEffect(() => {
    inputRefs.current[0]?.focus();
  }, []);

  useEffect(() => {
    if (countdown > 0 && !canResend) {
      const timer = setTimeout(() => setCountdown((c) => c - 1), 1000);
      return () => clearTimeout(timer);
    }
    if (countdown === 0 && !canResend) {
      setCanResend(true);
    }
  }, [countdown, canResend]);

  useEffect(() => {
    const session = sessionStorage.getItem(ADMIN_SESSION_KEY);
    if (session) {
      try {
        const data = JSON.parse(session);
        if (data.telegramCodeSent) return;
      } catch {}
    }
    sendTelegramCode();
  }, []);

  const sendTelegramCode = async () => {
    try {
      const session = sessionStorage.getItem(ADMIN_SESSION_KEY);
      if (!session) return;
      const { email } = JSON.parse(session);

      const res = await fetch('/api/admin/send-telegram-code', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });

      const body = await res.json();
      if (res.ok && body.success) {
        const sessionData = JSON.parse(sessionStorage.getItem(ADMIN_SESSION_KEY) || '{}');
        sessionData.telegramCodeSent = true;
        sessionStorage.setItem(ADMIN_SESSION_KEY, JSON.stringify(sessionData));
      }
    } catch {}
  };

  const handleChange = (index: number, value: string) => {
    if (value && !/^\d$/.test(value)) return;
    const newCode = [...code];
    newCode[index] = value;
    setCode(newCode);
    setError('');

    if (value && index < 5) {
      inputRefs.current[index + 1]?.focus();
    }
  };

  const handleKeyDown = (index: number, e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Backspace' && !code[index] && index > 0) {
      inputRefs.current[index - 1]?.focus();
    }
    if (e.key === 'Enter') {
      handleVerify();
    }
  };

  const handlePaste = (e: ClipboardEvent<HTMLInputElement>) => {
    e.preventDefault();
    const pasted = e.clipboardData.getData('text').replace(/\D/g, '').slice(0, 6);
    if (!pasted) return;
    const newCode = Array(6).fill('');
    for (let i = 0; i < pasted.length; i++) {
      newCode[i] = pasted[i];
    }
    setCode(newCode);
    const nextIndex = Math.min(pasted.length, 5);
    inputRefs.current[nextIndex]?.focus();
  };

  const handleVerify = async () => {
    const fullCode = code.join('');
    if (fullCode.length !== 6) {
      setError('يرجى إدخال الرمز المكون من 6 أرقام');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const session = sessionStorage.getItem(ADMIN_SESSION_KEY);
      if (!session) {
        router.replace('/zerocold/login');
        return;
      }
      const { email } = JSON.parse(session);

      const res = await fetch('/api/admin/verify-telegram', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, code: fullCode }),
      });

      const body = await res.json();

      if (!res.ok || !body.success) {
        setError(body.message || 'رمز التحقق غير صحيح');
        setCode(Array(6).fill(''));
        inputRefs.current[0]?.focus();
        return;
      }

      const sessionData = JSON.parse(sessionStorage.getItem(ADMIN_SESSION_KEY) || '{}');
      sessionData.step = 'telegram';
      sessionData.telegramVerified = true;
      sessionStorage.setItem(ADMIN_SESSION_KEY, JSON.stringify(sessionData));

      router.push('/zerocold/verify-master');
    } catch {
      setError('حدث خطأ في الاتصال بالخادم');
    } finally {
      setLoading(false);
    }
  };

  const handleResend = async () => {
    if (!canResend) return;
    setCanResend(false);
    setCountdown(RESEND_COOLDOWN);
    setCode(Array(6).fill(''));
    setError('');
    await sendTelegramCode();
  };

  const handleBack = () => {
    sessionStorage.removeItem(ADMIN_SESSION_KEY);
    router.push('/zerocold/login');
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-[#0a0a0f] to-[#1a0f0a] p-4">
      <div className="w-full max-w-sm">
        <button
          onClick={handleBack}
          className="flex items-center gap-1.5 text-amber-600/60 hover:text-amber-400 text-sm mb-6 transition-colors"
        >
          <ArrowLeft size={16} />
          العودة لتسجيل الدخول
        </button>

        <div className="text-center mb-8">
          <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-sky-600 to-blue-700 flex items-center justify-center mx-auto mb-4 shadow-lg shadow-sky-900/30">
            <MessageCircle className="w-8 h-8 text-white" />
          </div>
          <h1 className="text-2xl font-bold text-amber-50">التحقق عبر التليجرام</h1>
          <p className="text-amber-400/60 text-sm mt-2 leading-relaxed max-w-xs mx-auto">
            تم إرسال رمز تحقق مكون من 6 أرقام إلى بوت التليجرام الخاص بك
          </p>
        </div>

        <div className="bg-[#12101a] border border-[#2a1f0a] rounded-2xl p-6 shadow-2xl">
          <div className="flex items-center justify-center gap-2.5 mb-6" dir="ltr">
            {code.map((digit, index) => (
              <input
                key={index}
                ref={(el) => {
                  inputRefs.current[index] = el;
                }}
                type="text"
                inputMode="numeric"
                maxLength={1}
                value={digit}
                onChange={(e) => handleChange(index, e.target.value)}
                onKeyDown={(e) => handleKeyDown(index, e)}
                onPaste={index === 0 ? handlePaste : undefined}
                className="w-11 h-14 text-center text-lg font-bold bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 focus:outline-none focus:border-amber-600 focus:ring-1 focus:ring-amber-600/30 transition-all"
              />
            ))}
          </div>

          {error && (
            <div className="bg-red-950/40 border border-red-800/40 text-red-400 text-sm rounded-xl px-4 py-2.5 text-center mb-4">
              {error}
            </div>
          )}

          <button
            onClick={handleVerify}
            disabled={loading || code.join('').length !== 6}
            className="w-full py-2.5 bg-gradient-to-l from-sky-600 to-blue-700 hover:from-sky-500 hover:to-blue-600 disabled:from-sky-800 disabled:to-blue-900 disabled:cursor-not-allowed text-white font-semibold rounded-xl transition-all text-sm shadow-lg shadow-sky-900/20 flex items-center justify-center gap-2"
          >
            {loading && <Loader2 size={18} className="animate-spin" />}
            {loading ? 'جاري التحقق...' : 'تحقق'}
          </button>

          <div className="mt-4 text-center">
            {canResend ? (
              <button
                onClick={handleResend}
                className="text-amber-500 hover:text-amber-400 text-sm transition-colors"
              >
                إعادة إرسال الرمز
              </button>
            ) : (
              <p className="text-amber-600/50 text-sm">
                إعادة الإرسال بعد {countdown} ثانية
              </p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import {
  Building2, Search, Loader2, ShieldAlert, RefreshCw,
  CheckCircle, XCircle, Eye, ChevronLeft
} from 'lucide-react';
import Link from 'next/link';

const ADMIN_TOKEN_KEY = 'zerocold_token';

interface Company {
  id: string;
  name: string;
  commercial_registration: string;
  tax_number: string;
  user_count: number;
  created_at: string;
  status: 'active' | 'suspended';
}

export default function ZerocoldCompaniesPage() {
  const router = useRouter();
  const [companies, setCompanies] = useState<Company[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  const fetchCompanies = async () => {
    setLoading(true);
    setError('');
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      if (!token) {
        router.replace('/zerocold/login');
        return;
      }

      const res = await fetch('/api/admin/companies', {
        headers: { Authorization: `Bearer ${token}` },
      });

      if (res.status === 401) {
        localStorage.removeItem(ADMIN_TOKEN_KEY);
        router.replace('/zerocold/login');
        return;
      }

      const body = await res.json();
      if (!body.success) {
        setError(body.message || 'حدث خطأ');
        return;
      }

      const rawCompanies = body.data?.companies ?? (Array.isArray(body.data) ? body.data : []);
      setCompanies(rawCompanies.map((c: any) => ({
        ...c,
        status: c.is_active ? 'active' : 'suspended',
      })));
    } catch {
      setError('حدث خطأ في الاتصال بالخادم');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCompanies();
  }, []);

  const toggleStatus = async (companyId: string, currentStatus: string) => {
    setActionLoading(companyId);
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      const res = await fetch('/api/admin/companies/toggle-status', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ companyId }),
      });

      const body = await res.json();

      if (!res.ok || !body.success) {
        if (body.masterRequired) {
          router.push('/zerocold/verify-master');
          return;
        }
        return;
      }

      setCompanies((prev) =>
        prev.map((c) =>
          c.id === companyId
            ? { ...c, status: currentStatus === 'active' ? 'suspended' : 'active' }
            : c
        )
      );
    } catch {} finally {
      setActionLoading(null);
    }
  };

  const filtered = companies.filter((c) =>
    c.name.toLowerCase().includes(search.toLowerCase()) ||
    c.commercial_registration?.toLowerCase().includes(search.toLowerCase()) ||
    c.tax_number?.toLowerCase().includes(search.toLowerCase())
  );

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center">
        <Loader2 size={32} className="text-amber-500 animate-spin" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0a0a0f]">
      <div className="max-w-6xl mx-auto px-4 py-6">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <Link href="/zerocold/" className="p-2 rounded-lg hover:bg-[#12101a] transition-all">
              <ChevronLeft size={18} className="text-amber-500/70" />
            </Link>
            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-sky-600 to-blue-700 flex items-center justify-center">
              <Building2 className="w-5 h-5 text-white" />
            </div>
            <div>
              <h1 className="text-lg font-bold text-amber-50">إدارة الشركات</h1>
              <p className="text-[0.7rem] text-amber-400/50">{companies.length} شركة</p>
            </div>
          </div>
          <button
            onClick={fetchCompanies}
            className="p-2 rounded-xl bg-[#12101a] border border-[#2a1f0a] text-amber-500/70 hover:text-amber-400 transition-all"
            title="تحديث"
          >
            <RefreshCw size={16} />
          </button>
        </div>

        <div className="relative mb-4">
          <Search size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-amber-600/50" />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="بحث عن شركة..."
            className="w-full pr-10 pl-4 py-2.5 bg-[#12101a] border border-[#2a1f0a] rounded-xl text-amber-50 placeholder-amber-700/50 focus:outline-none focus:border-amber-600 focus:ring-1 focus:ring-amber-600/30 transition-all text-sm"
          />
        </div>

        {error && (
          <div className="bg-red-950/40 border border-red-800/40 text-red-400 text-sm rounded-xl px-4 py-2.5 text-center mb-4">
            {error}
          </div>
        )}

        {filtered.length === 0 && !error ? (
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-8 text-center">
            <Building2 size={32} className="text-amber-600/30 mx-auto mb-2" />
            <p className="text-amber-600/50 text-sm">لا توجد شركات مطابقة للبحث</p>
          </div>
        ) : (
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-[#2a1f0a]">
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">اسم الشركة</th>
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">رقم السجل</th>
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">الرقم الضريبي</th>
                    <th className="text-center p-3 text-[0.7rem] text-amber-500/60 font-medium">المستخدمين</th>
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">تاريخ الإنشاء</th>
                    <th className="text-center p-3 text-[0.7rem] text-amber-500/60 font-medium">الحالة</th>
                    <th className="text-center p-3 text-[0.7rem] text-amber-500/60 font-medium">الإجراءات</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map((company) => (
                    <tr key={company.id} className="border-b border-[#1f1725] last:border-0 hover:bg-[#1a1625] transition-all">
                      <td className="p-3">
                        <span className="text-sm text-amber-200 font-medium">{company.name}</span>
                      </td>
                      <td className="p-3">
                        <span className="text-xs text-amber-400/60 font-mono">{company.commercial_registration || '--'}</span>
                      </td>
                      <td className="p-3">
                        <span className="text-xs text-amber-400/60 font-mono">{company.tax_number || '--'}</span>
                      </td>
                      <td className="p-3 text-center">
                        <span className="text-xs text-amber-400/80 font-mono">{company.user_count}</span>
                      </td>
                      <td className="p-3">
                        <span className="text-xs text-amber-400/60">{company.created_at}</span>
                      </td>
                      <td className="p-3 text-center">
                        <span
                          className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[0.65rem] font-medium ${
                            company.status === 'active'
                              ? 'bg-emerald-950/40 text-emerald-400 border border-emerald-800/30'
                              : 'bg-red-950/40 text-red-400 border border-red-800/30'
                          }`}
                        >
                          {company.status === 'active' ? (
                            <CheckCircle size={10} />
                          ) : (
                            <XCircle size={10} />
                          )}
                          {company.status === 'active' ? 'نشط' : 'موقوف'}
                        </span>
                      </td>
                      <td className="p-3 text-center">
                        <div className="flex items-center justify-center gap-1.5">
                          <button
                            onClick={() => toggleStatus(company.id, company.status)}
                            disabled={actionLoading === company.id}
                            className={`px-2.5 py-1 rounded-lg text-[0.65rem] font-medium transition-all border ${
                              company.status === 'active'
                                ? 'bg-red-950/20 text-red-400/70 border-red-800/20 hover:bg-red-950/40 hover:text-red-400'
                                : 'bg-emerald-950/20 text-emerald-400/70 border-emerald-800/20 hover:bg-emerald-950/40 hover:text-emerald-400'
                            }`}
                          >
                            {actionLoading === company.id ? (
                              <Loader2 size={12} className="animate-spin" />
                            ) : company.status === 'active' ? (
                              'تعليق'
                            ) : (
                              'تفعيل'
                            )}
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import {
  Users, Search, Loader2, ShieldAlert, RefreshCw,
  CheckCircle, XCircle, ChevronLeft, Filter, Eye
} from 'lucide-react';
import Link from 'next/link';

const ADMIN_TOKEN_KEY = 'zerocold_token';

interface AppUser {
  id: string;
  name: string;
  email: string;
  company_name: string;
  company_id: string;
  role: string;
  status: 'active' | 'suspended';
  last_login: string | null;
}

export default function ZerocoldUsersPage() {
  const router = useRouter();
  const [users, setUsers] = useState<AppUser[]>([]);
  const [companies, setCompanies] = useState<{ id: string; name: string }[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [companyFilter, setCompanyFilter] = useState('');
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const [selectedUser, setSelectedUser] = useState<AppUser | null>(null);
  const [userActivity, setUserActivity] = useState<{ action: string; timestamp: string }[]>([]);
  const [activityLoading, setActivityLoading] = useState(false);

  const fetchData = async () => {
    setLoading(true);
    setError('');
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      if (!token) {
        router.replace('/zerocold/login');
        return;
      }

      const [usersRes, companiesRes] = await Promise.all([
        fetch('/api/admin/users', { headers: { Authorization: `Bearer ${token}` } }),
        fetch('/api/admin/companies', { headers: { Authorization: `Bearer ${token}` } }),
      ]);

      if (usersRes.status === 401) {
        localStorage.removeItem(ADMIN_TOKEN_KEY);
        router.replace('/zerocold/login');
        return;
      }

      const usersBody = await usersRes.json();
      const companiesBody = await companiesRes.json();

      if (!usersBody.success) {
        setError(usersBody.message || 'حدث خطأ');
        return;
      }

      const rawUsers = usersBody.data?.users ?? (Array.isArray(usersBody.data) ? usersBody.data : []);
      setUsers(rawUsers.map((u: any) => ({
        ...u,
        status: u.is_active ? 'active' : 'suspended',
      })));
      if (companiesBody.success) {
        const companiesData = companiesBody.data?.companies ?? (Array.isArray(companiesBody.data) ? companiesBody.data : []);
        setCompanies(companiesData);
      }
    } catch {
      setError('حدث خطأ في الاتصال بالخادم');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const toggleStatus = async (userId: string) => {
    setActionLoading(userId);
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      const res = await fetch('/api/admin/users/toggle-status', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ userId }),
      });

      const body = await res.json();
      if (!res.ok || !body.success) return;

      setUsers((prev) =>
        prev.map((u) =>
          u.id === userId
            ? { ...u, status: u.status === 'active' ? 'suspended' : 'active' }
            : u
        )
      );
    } catch {} finally {
      setActionLoading(null);
    }
  };

  const showUserActivity = async (user: AppUser) => {
    setSelectedUser(user);
    setActivityLoading(true);
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      const res = await fetch(`/api/admin/users/${user.id}/activity`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const body = await res.json();
      setUserActivity(body.success ? body.data : []);
    } catch {
      setUserActivity([]);
    } finally {
      setActivityLoading(false);
    }
  };

  const filtered = users.filter((u) => {
    const matchesSearch =
      u.name.toLowerCase().includes(search.toLowerCase()) ||
      u.email.toLowerCase().includes(search.toLowerCase());
    const matchesCompany = !companyFilter || u.company_id === companyFilter;
    return matchesSearch && matchesCompany;
  });

  const roleLabels: Record<string, string> = {
    admin: 'مدير',
    accountant: 'محاسب',
    manager: 'مشرف',
    supervisor: 'مراقب',
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center">
        <Loader2 size={32} className="text-amber-500 animate-spin" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0a0a0f]">
      <div className="max-w-6xl mx-auto px-4 py-6">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <Link href="/zerocold/" className="p-2 rounded-lg hover:bg-[#12101a] transition-all">
              <ChevronLeft size={18} className="text-amber-500/70" />
            </Link>
            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-emerald-600 to-green-700 flex items-center justify-center">
              <Users className="w-5 h-5 text-white" />
            </div>
            <div>
              <h1 className="text-lg font-bold text-amber-50">إدارة المستخدمين</h1>
              <p className="text-[0.7rem] text-amber-400/50">{users.length} مستخدم</p>
            </div>
          </div>
          <button
            onClick={fetchData}
            className="p-2 rounded-xl bg-[#12101a] border border-[#2a1f0a] text-amber-500/70 hover:text-amber-400 transition-all"
            title="تحديث"
          >
            <RefreshCw size={16} />
          </button>
        </div>

        <div className="flex items-center gap-3 mb-4">
          <div className="relative flex-1">
            <Search size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-amber-600/50" />
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="بحث عن مستخدم..."
              className="w-full pr-10 pl-4 py-2.5 bg-[#12101a] border border-[#2a1f0a] rounded-xl text-amber-50 placeholder-amber-700/50 focus:outline-none focus:border-amber-600 focus:ring-1 focus:ring-amber-600/30 transition-all text-sm"
            />
          </div>
          <div className="relative">
            <Filter size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-amber-600/50 pointer-events-none" />
            <select
              value={companyFilter}
              onChange={(e) => setCompanyFilter(e.target.value)}
              className="pr-10 pl-4 py-2.5 bg-[#12101a] border border-[#2a1f0a] rounded-xl text-amber-50 focus:outline-none focus:border-amber-600 focus:ring-1 focus:ring-amber-600/30 transition-all text-sm appearance-none cursor-pointer"
            >
              <option value="">كل الشركات</option>
              {companies.map((c) => (
                <option key={c.id} value={c.id}>{c.name}</option>
              ))}
            </select>
          </div>
        </div>

        {error && (
          <div className="bg-red-950/40 border border-red-800/40 text-red-400 text-sm rounded-xl px-4 py-2.5 text-center mb-4">
            {error}
          </div>
        )}

        {filtered.length === 0 && !error ? (
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-8 text-center">
            <Users size={32} className="text-amber-600/30 mx-auto mb-2" />
            <p className="text-amber-600/50 text-sm">لا يوجد مستخدمون مطابقون للبحث</p>
          </div>
        ) : (
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-[#2a1f0a]">
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">الاسم</th>
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">البريد الإلكتروني</th>
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">الشركة</th>
                    <th className="text-center p-3 text-[0.7rem] text-amber-500/60 font-medium">الدور</th>
                    <th className="text-center p-3 text-[0.7rem] text-amber-500/60 font-medium">الحالة</th>
                    <th className="text-right p-3 text-[0.7rem] text-amber-500/60 font-medium">آخر دخول</th>
                    <th className="text-center p-3 text-[0.7rem] text-amber-500/60 font-medium">الإجراءات</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map((user) => (
                    <tr key={user.id} className="border-b border-[#1f1725] last:border-0 hover:bg-[#1a1625] transition-all">
                      <td className="p-3">
                        <span className="text-sm text-amber-200 font-medium">{user.name}</span>
                      </td>
                      <td className="p-3">
                        <span className="text-xs text-amber-400/60 font-mono" dir="ltr">{user.email}</span>
                      </td>
                      <td className="p-3">
                        <span className="text-xs text-amber-400/80">{user.company_name}</span>
                      </td>
                      <td className="p-3 text-center">
                        <span className="text-xs text-amber-400/60">{roleLabels[user.role] || user.role}</span>
                      </td>
                      <td className="p-3 text-center">
                        <span
                          className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[0.65rem] font-medium ${
                            user.status === 'active'
                              ? 'bg-emerald-950/40 text-emerald-400 border border-emerald-800/30'
                              : 'bg-red-950/40 text-red-400 border border-red-800/30'
                          }`}
                        >
                          {user.status === 'active' ? (
                            <CheckCircle size={10} />
                          ) : (
                            <XCircle size={10} />
                          )}
                          {user.status === 'active' ? 'نشط' : 'موقوف'}
                        </span>
                      </td>
                      <td className="p-3">
                        <span className="text-xs text-amber-400/60">{user.last_login || '--'}</span>
                      </td>
                      <td className="p-3 text-center">
                        <div className="flex items-center justify-center gap-1.5">
                          <button
                            onClick={() => showUserActivity(user)}
                            className="px-2.5 py-1 rounded-lg bg-sky-950/20 text-sky-400/70 border border-sky-800/20 hover:bg-sky-950/40 hover:text-sky-400 text-[0.65rem] font-medium transition-all"
                          >
                            <Eye size={12} className="inline ml-1" />
                            النشاطات
                          </button>
                          <button
                            onClick={() => toggleStatus(user.id)}
                            disabled={actionLoading === user.id}
                            className={`px-2.5 py-1 rounded-lg text-[0.65rem] font-medium transition-all border ${
                              user.status === 'active'
                                ? 'bg-red-950/20 text-red-400/70 border-red-800/20 hover:bg-red-950/40 hover:text-red-400'
                                : 'bg-emerald-950/20 text-emerald-400/70 border-emerald-800/20 hover:bg-emerald-950/40 hover:text-emerald-400'
                            }`}
                          >
                            {actionLoading === user.id ? (
                              <Loader2 size={12} className="animate-spin" />
                            ) : user.status === 'active' ? (
                              'تعليق'
                            ) : (
                              'تفعيل'
                            )}
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {selectedUser && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setSelectedUser(null)} />
            <div className="relative bg-[#12101a] border border-[#2a1f0a] rounded-2xl p-5 w-full max-w-md shadow-2xl modal-content">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-sm font-bold text-amber-200">نشاطات المستخدم</h3>
                <button
                  onClick={() => setSelectedUser(null)}
                  className="text-amber-600/60 hover:text-amber-400 text-sm transition-colors"
                >
                  إغلاق
                </button>
              </div>
              <p className="text-xs text-amber-400/60 mb-4">
                {selectedUser.name} — {selectedUser.email}
              </p>
              {activityLoading ? (
                <div className="flex justify-center py-6">
                  <Loader2 size={20} className="text-amber-500 animate-spin" />
                </div>
              ) : userActivity.length > 0 ? (
                <div className="space-y-1 max-h-60 overflow-y-auto">
                  {userActivity.map((act, i) => (
                    <div key={i} className="flex items-center justify-between p-2 rounded-lg bg-[#1a1625]">
                      <span className="text-xs text-amber-300/70">{act.action}</span>
                      <span className="text-[0.65rem] text-amber-600/40">{act.timestamp}</span>
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-amber-600/50 text-xs text-center py-6">لا توجد نشاطات مسجلة</p>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import {
  Database, HardDrive, Table2, Upload, Download, Loader2,
  ShieldAlert, RefreshCw, ChevronLeft, AlertTriangle, CheckCircle, XCircle
} from 'lucide-react';
import Link from 'next/link';

const ADMIN_TOKEN_KEY = 'zerocold_token';

interface TableInfo {
  name: string;
  row_count: number;
  size: string;
}

interface DbInfo {
  dbSize: string;
  dbPath: string;
  healthStatus: string;
  tables: TableInfo[];
  indexHealth: { total: number; missing: number; issues: string[] };
  slowQueries: { query: string; avg_time: string; count: number }[];
}

export default function ZerocoldDatabasePage() {
  const router = useRouter();
  const [dbInfo, setDbInfo] = useState<DbInfo | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [backingUp, setBackingUp] = useState(false);
  const [restoring, setRestoring] = useState(false);
  const [backupMessage, setBackupMessage] = useState('');
  const [restoreMessage, setRestoreMessage] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const fetchDbInfo = async () => {
    setLoading(true);
    setError('');
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      if (!token) {
        router.replace('/zerocold/login');
        return;
      }

      const res = await fetch('/api/admin/database', {
        headers: { Authorization: `Bearer ${token}` },
      });

      if (res.status === 401) {
        localStorage.removeItem(ADMIN_TOKEN_KEY);
        router.replace('/zerocold/login');
        return;
      }

      const body = await res.json();
      if (!body.success) {
        setError(body.message || 'حدث خطأ');
        return;
      }

      setDbInfo(body.data);
    } catch {
      setError('حدث خطأ في الاتصال بالخادم');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDbInfo();
  }, []);

  const handleBackup = async () => {
    setBackingUp(true);
    setBackupMessage('');
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      const res = await fetch('/api/admin/database/backup', {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
      });

      const body = await res.json();
      if (body.success) {
        setBackupMessage('تم إنشاء النسخة الاحتياطية وإرسالها إلى التليجرام بنجاح');
      } else {
        setBackupMessage(body.message || 'فشل إنشاء النسخة الاحتياطية');
      }
    } catch {
      setBackupMessage('حدث خطأ في الاتصال بالخادم');
    } finally {
      setBackingUp(false);
    }
  };

  const handleRestore = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setRestoring(true);
    setRestoreMessage('');
    try {
      const token = localStorage.getItem(ADMIN_TOKEN_KEY);
      const formData = new FormData();
      formData.append('backup', file);

      const res = await fetch('/api/admin/database/restore', {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
        body: formData,
      });

      const body = await res.json();
      if (body.success) {
        setRestoreMessage('تمت استعادة قاعدة البيانات بنجاح');
        fetchDbInfo();
      } else {
        setRestoreMessage(body.message || 'فشلت عملية الاستعادة');
      }
    } catch {
      setRestoreMessage('حدث خطأ في الاتصال بالخادم');
    } finally {
      setRestoring(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center">
        <Loader2 size={32} className="text-amber-500 animate-spin" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0a0a0f]">
      <div className="max-w-6xl mx-auto px-4 py-6">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <Link href="/zerocold/" className="p-2 rounded-lg hover:bg-[#12101a] transition-all">
              <ChevronLeft size={18} className="text-amber-500/70" />
            </Link>
            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-violet-600 to-purple-700 flex items-center justify-center">
              <Database className="w-5 h-5 text-white" />
            </div>
            <div>
              <h1 className="text-lg font-bold text-amber-50">قاعدة البيانات</h1>
              <p className="text-[0.7rem] text-amber-400/50">إدارة قاعدة البيانات والنسخ الاحتياطي</p>
            </div>
          </div>
          <button
            onClick={fetchDbInfo}
            className="p-2 rounded-xl bg-[#12101a] border border-[#2a1f0a] text-amber-500/70 hover:text-amber-400 transition-all"
            title="تحديث"
          >
            <RefreshCw size={16} />
          </button>
        </div>

        {error && (
          <div className="bg-red-950/40 border border-red-800/40 text-red-400 text-sm rounded-xl px-4 py-2.5 text-center mb-4">
            {error}
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 mb-6">
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-4">
            <div className="flex items-center gap-2 mb-2">
              <HardDrive size={16} className="text-amber-500/70" />
              <span className="text-xs text-amber-400/60 font-medium">حجم قاعدة البيانات</span>
            </div>
            <p className="text-lg font-bold text-amber-50 font-mono">{dbInfo?.dbSize ?? '--'}</p>
          </div>
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-4">
            <div className="flex items-center gap-2 mb-2">
              <Table2 size={16} className="text-amber-500/70" />
              <span className="text-xs text-amber-400/60 font-medium">عدد الجداول</span>
            </div>
            <p className="text-lg font-bold text-amber-50 font-mono">{dbInfo?.tables?.length ?? 0}</p>
          </div>
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-4">
            <div className="flex items-center gap-2 mb-2">
              {dbInfo?.healthStatus === 'good' ? (
                <CheckCircle size={16} className="text-emerald-400" />
              ) : (
                <AlertTriangle size={16} className="text-amber-400" />
              )}
              <span className="text-xs text-amber-400/60 font-medium">حالة قاعدة البيانات</span>
            </div>
            <p className="text-sm font-bold text-amber-50">
              {dbInfo?.healthStatus === 'good' ? 'سليمة' : dbInfo?.healthStatus === 'warning' ? 'تحذير' : '--'}
            </p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-5">
            <h2 className="text-sm font-bold text-amber-300/80 mb-3">النسخ الاحتياطي والاستعادة</h2>
            <div className="space-y-3">
              <button
                onClick={handleBackup}
                disabled={backingUp}
                className="w-full flex items-center justify-center gap-2 py-2.5 bg-gradient-to-l from-amber-600 to-orange-700 hover:from-amber-500 hover:to-orange-600 disabled:from-amber-800 disabled:to-orange-900 disabled:cursor-not-allowed text-white font-semibold rounded-xl transition-all text-sm shadow-lg shadow-amber-900/20"
              >
                {backingUp ? (
                  <Loader2 size={16} className="animate-spin" />
                ) : (
                  <Download size={16} />
                )}
                {backingUp ? 'جاري إنشاء النسخة...' : 'نسخ احتياطي'}
              </button>

              <input
                ref={fileInputRef}
                type="file"
                accept=".db,.sqlite,.sqlite3,.backup"
                onChange={handleRestore}
                className="hidden"
              />
              <button
                onClick={() => fileInputRef.current?.click()}
                disabled={restoring}
                className="w-full flex items-center justify-center gap-2 py-2.5 bg-[#1a1625] border border-[#2a1f0a] hover:border-[#3a2f1a] disabled:opacity-50 disabled:cursor-not-allowed text-amber-300/80 font-semibold rounded-xl transition-all text-sm"
              >
                {restoring ? (
                  <Loader2 size={16} className="animate-spin" />
                ) : (
                  <Upload size={16} />
                )}
                {restoring ? 'جاري الاستعادة...' : 'استعادة نسخة احتياطية'}
              </button>

              {backupMessage && (
                <div className={`text-xs text-center px-3 py-2 rounded-lg ${
                  backupMessage.includes('نجاح') ? 'bg-emerald-950/40 text-emerald-400' : 'bg-red-950/40 text-red-400'
                }`}>
                  {backupMessage}
                </div>
              )}

              {restoreMessage && (
                <div className={`text-xs text-center px-3 py-2 rounded-lg ${
                  restoreMessage.includes('نجاح') ? 'bg-emerald-950/40 text-emerald-400' : 'bg-red-950/40 text-red-400'
                }`}>
                  {restoreMessage}
                </div>
              )}
            </div>
          </div>

          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-xl p-5">
            <h2 className="text-sm font-bold text-amber-300/80 mb-3">مؤشرات قاعدة البيانات</h2>
            <div className="space-y-2">
              <div className="flex items-center justify-between p-2.5 rounded-lg bg-[#1a1625] border border-[#2a1f0a]">
