                  {{ active: 'نشط', trial: 'تجريبي', expired: 'منتهي', cancelled: 'ملغي' }[sub.status] || sub.status}
                </span>
                <span className={`text-xs ${sub.auto_renew ? 'text-green-400' : 'text-amber-600'}`}>{sub.auto_renew ? 'تجديد تلقائي' : 'يدوي'}</span>
