import { NextRequest } from 'next/server';
import { success, error, serverError, parseBody } from '@/lib/api-helpers';
import { query } from '@/lib/db';
import { verifyPassword } from '@/lib/auth';
import { adminLoginSchema } from '@/lib/validation';
import { sendTelegramCode } from '@/lib/telegram';
import { generateId } from '@/lib/utils';
import { createAdminSession, updateAdminSession } from '@/lib/admin-session';

export async function POST(request: NextRequest) {
  try {
    const body = await parseBody<{ email: string; password: string }>(request);
    const parsed = adminLoginSchema.safeParse(body);
    if (!parsed.success) {
      return error('البريد الإلكتروني أو كلمة المرور غير صالحة');
    }

    const { email, password } = parsed.data;

    const res = await query(
      `SELECT id, name, email, password_hash, is_active
       FROM admin_users
       WHERE email = LOWER($1)`,
      [email]
    );

    if (res.rows.length === 0) {
      return error('البريد الإلكتروني أو كلمة المرور غير صحيحة', 401);
    }

    const admin = res.rows[0];

    if (!admin.is_active) {
      return error('هذا الحساب غير نشط', 403);
    }

    const valid = await verifyPassword(password, admin.password_hash);
    if (!valid) {
      return error('البريد الإلكتروني أو كلمة المرور غير صحيحة', 401);
    }

    const sessionId = generateId();
    const code = String(Math.floor(100000 + Math.random() * 900000));

    createAdminSession(sessionId, admin.email, code);

    await sendTelegramCode(code);

    updateAdminSession(sessionId, { codeSent: true });

    const response = success({
      message: 'تم إرسال رمز التحقق إلى تيليجرام',
      email: admin.email,
    });

    response.cookies.set('admin_session', sessionId, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 1800,
      path: '/',
    });

    return response;
  } catch (err) {
    return serverError(err);
  }
}

import { NextRequest } from 'next/server';
import { success, error } from '@/lib/api-helpers';
import { verifyToken } from '@/lib/auth';
import { query } from '@/lib/db';

export async function GET(request: NextRequest) {
  const authHeader = request.headers.get('authorization') || '';
  const token = authHeader.startsWith('Bearer ') ? authHeader.slice(7) : '';

  if (!token) {
    return error('Unauthorized', 401);
  }

  const payload = verifyToken(token);
  if (!payload) {
    return error('Invalid or expired token', 401);
  }

  const res = await query(
    `SELECT id, name, email, is_active
     FROM admin_users
     WHERE id = $1`,
    [payload.userId]
  );

  if (res.rows.length === 0) {
    return error('Admin not found', 401);
  }

  const admin = res.rows[0];

  if (!admin.is_active) {
    return error('Account inactive', 403);
  }

  return success({
    id: admin.id,
    name: admin.name,
    email: admin.email,
    role: payload.role,
  });
}

import { NextRequest } from 'next/server';
import { success, error, serverError, parseBody } from '@/lib/api-helpers';
import { query, transaction } from '@/lib/db';
import { verifyPassword, createToken } from '@/lib/auth';
import { getAdminSession, deleteAdminSession } from '@/lib/admin-session';

export async function POST(request: NextRequest) {
  try {
    const { email, masterPassword } = await parseBody<{ email: string; masterPassword: string }>(request);

    if (!masterPassword) {
      return error('كلمة المرور الرئيسية مطلوبة');
    }

    const sessionId = request.cookies.get('admin_session')?.value;
    if (!sessionId) {
      return error('انتهت صلاحية الجلسة. يرجى تسجيل الدخول مرة أخرى', 401);
    }

    const session = getAdminSession(sessionId);
    if (!session) {
      return error('انتهت صلاحية الجلسة. يرجى تسجيل الدخول مرة أخرى', 401);
    }

    if (session.email !== email.trim().toLowerCase()) {
      return error('البريد الإلكتروني غير متطابق مع الجلسة', 401);
    }

    if (session.step !== 'telegram_verified') {
      return error('يرجى التحقق من رمز تيليجرام أولاً', 401);
    }

    const res = await query(
      `SELECT id, name, email, master_password_hash, is_active
       FROM admin_users
       WHERE email = LOWER($1)`,
      [session.email]
    );

    if (res.rows.length === 0) {
      return error('المستخدم غير موجود', 401);
    }

    const admin = res.rows[0];

    if (!admin.is_active) {
      return error('هذا الحساب غير نشط', 403);
    }

    if (!admin.master_password_hash) {
      return error('لم يتم تعيين كلمة مرور رئيسية لهذا الحساب', 403);
    }

    const valid = await verifyPassword(masterPassword, admin.master_password_hash);
    if (!valid) {
      return error('كلمة المرور الرئيسية غير صحيحة', 401);
    }

    const token = createToken(admin.id, 'superadmin');

    deleteAdminSession(sessionId);

    const response = success({
      message: 'تم تسجيل الدخول بنجاح',
      admin: {
        id: admin.id,
        name: admin.name,
        email: admin.email,
        role: 'superadmin',
      },
      token,
    });

    response.cookies.set('admin_token', token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      maxAge: 86400,
      path: '/',
    });

    response.cookies.set('admin_session', '', {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 0,
      path: '/',
    });

    return response;
  } catch (err) {
    return serverError(err);
  }
}

import { NextRequest } from 'next/server';
import { success, error, serverError, parseBody } from '@/lib/api-helpers';
import { getAdminSession, updateAdminSession } from '@/lib/admin-session';

export async function POST(request: NextRequest) {
  try {
    const { email, code } = await parseBody<{ email: string; code: string }>(request);

    if (!code || !/^\d{6}$/.test(code)) {
      return error('رمز التحقق غير صالح');
    }

    const sessionId = request.cookies.get('admin_session')?.value;
    if (!sessionId) {
      return error('انتهت صلاحية الجلسة. يرجى تسجيل الدخول مرة أخرى', 401);
    }

    const session = getAdminSession(sessionId);
    if (!session) {
      return error('انتهت صلاحية الجلسة. يرجى تسجيل الدخول مرة أخرى', 401);
    }

    if (session.email !== email.trim().toLowerCase()) {
      return error('البريد الإلكتروني غير متطابق مع الجلسة', 401);
    }

    if (session.code !== code) {
      return error('رمز التحقق غير صحيح', 401);
    }

    updateAdminSession(sessionId, { step: 'telegram_verified' });

    return success({ message: 'تم التحقق من رمز تيليجرام بنجاح' });
  } catch (err) {
    return serverError(err);
  }
}

import { NextRequest } from 'next/server';
import { success, error, serverError } from '@/lib/api-helpers';
import { sendTelegramCode } from '@/lib/telegram';
import { getAdminSession } from '@/lib/admin-session';

export async function POST(request: NextRequest) {
  try {
    const { email } = await request.json();
    if (!email) return error('Email required');

    const sessionId = request.cookies.get('admin_session')?.value;
    if (!sessionId) return error('انتهت صلاحية الجلسة', 401);

    const session = getAdminSession(sessionId);
    if (!session) return error('انتهت صلاحية الجلسة', 401);
    if (session.email !== email) return error('البريد الإلكتروني غير متطابق مع الجلسة', 401);

    if (session.codeSent) {
      return success({ message: 'تم إرسال الرمز مسبقاً', alreadySent: true });
    }

    session.codeSent = true;
    await sendTelegramCode(session.code);
    return success({ message: 'تم إرسال رمز التحقق' });
  } catch (err) {
    return serverError(err);
  }
}

import { NextRequest } from 'next/server';
import { success, unauthorized, serverError } from '@/lib/api-helpers';
import { query } from '@/lib/db';
import { verifyToken } from '@/lib/auth';

export async function GET(request: NextRequest) {
  try {
    const token = request.cookies.get('admin_token')?.value;
    if (!token) return unauthorized();

    const payload = verifyToken(token);
    if (!payload || payload.role !== 'superadmin') return unauthorized();

    const [companiesRes, usersRes, dbSizeRes, lastLoginRes, activityRes] = await Promise.all([
      query('SELECT COUNT(*)::int as count FROM companies'),
      query('SELECT COUNT(*)::int as count FROM users'),
      query('SELECT pg_database_size(current_database())::bigint as size'),
      query(
        `SELECT last_login FROM admin_users WHERE id = $1`,
        [payload.userId]
      ),
      query(
        `SELECT action, details, created_at
         FROM admin_audit_log
         ORDER BY created_at DESC
         LIMIT 10`
      ),
    ]);

    const dbSizeBytes = dbSizeRes.rows[0].size;

    return success({
      companiesCount: companiesRes.rows[0].count,
      usersCount: usersRes.rows[0].count,
      dbSize: formatBytes(dbSizeBytes),
      lastLogin: lastLoginRes.rows[0]?.last_login
        ? new Date(lastLoginRes.rows[0].last_login).toLocaleString('ar-SA')
        : '--',
      recentActivity: activityRes.rows.map((row: any) => ({
        action: row.action,
        details: row.details || '',
        timestamp: new Date(row.created_at).toLocaleString('ar-SA'),
      })),
      systemHealth: {
        dbStatus: 'متصل',
        apiResponseTime: '< 100ms',
        uptime: formatUptime(process.uptime()),
      },
    });
  } catch (err) {
    return serverError(err);
  }
}

function formatBytes(bytes: number): string {
  if (!bytes) return '0 B';
  const units = ['B', 'KB', 'MB', 'GB', 'TB'];
  let i = 0;
  let size = bytes;
  while (size >= 1024 && i < units.length - 1) {
    size /= 1024;
    i++;
  }
  return `${size.toFixed(i === 0 ? 0 : 1)} ${units[i]}`;
}

function formatUptime(seconds: number): string {
  const days = Math.floor(seconds / 86400);
  const hours = Math.floor((seconds % 86400) / 3600);
  const mins = Math.floor((seconds % 3600) / 60);
  if (days > 0) return `${days}ي ${hours}س`;
  if (hours > 0) return `${hours}س ${mins}د`;
  return `${mins}د`;
}

