const ADMIN_TOKEN_KEY = 'zerocold_token';

interface Plan {
  id: string; code: string; name: string; description: string;
  price_monthly: number; price_yearly: number; max_users: number;
  max_projects: number; is_active: boolean; sort_order: number;
}

export default function PlansPage() {
  const router = useRouter();
  const [plans, setPlans] = useState<Plan[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ code: '', name: '', description: '', price_monthly: 0, price_yearly: 0, max_users: 1, max_projects: 0 });
  const [saving, setSaving] = useState(false);

  const fetchPlans = async () => {
    const token = localStorage.getItem(ADMIN_TOKEN_KEY);
    if (!token) { router.replace('/zerocold/login'); return; }
    try {
      const res = await fetch('/api/admin/subscription-plans', { headers: { Authorization: `Bearer ${token}` } });
      const body = await res.json();
      if (body.success) setPlans(body.data);
    } finally { setLoading(false); }
  };

  useEffect(() => { fetchPlans(); }, []);

  const savePlan = async () => {
    setSaving(true);
    const token = localStorage.getItem(ADMIN_TOKEN_KEY);
    try {
      const res = await fetch('/api/admin/subscription-plans', {
        method: 'POST', headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify(form),
      });
      const body = await res.json();
      if (body.success) { setShowForm(false); fetchPlans(); setForm({ code: '', name: '', description: '', price_monthly: 0, price_yearly: 0, max_users: 1, max_projects: 0 }); }
    } finally { setSaving(false); }
  };

  const toggleActive = async (plan: Plan) => {
    const token = localStorage.getItem(ADMIN_TOKEN_KEY);
    await fetch(`/api/admin/subscription-plans/${plan.id}`, {
      method: 'PUT', headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ isActive: !plan.is_active }),
    });
    fetchPlans();
  };

  if (loading) return <div className="flex items-center justify-center h-64"><Loader2 className="w-8 h-8 animate-spin text-amber-500" /></div>;

  return (
    <div className="p-6 max-w-4xl mx-auto" dir="rtl">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-xl font-bold text-amber-50">خطط الاشتراك</h1>
          <p className="text-amber-400/60 text-sm">إدارة خطط الأسعار والميزات</p>
        </div>
        <button onClick={() => setShowForm(true)} className="px-4 py-2 bg-amber-600 hover:bg-amber-500 text-white rounded-xl text-sm flex items-center gap-2 transition-colors"><Plus size={16} />إضافة خطة</button>
      </div>

      <div className="grid gap-4">
        {plans.map((plan) => (
          <div key={plan.id} className="bg-[#12101a] border border-[#2a1f0a] rounded-2xl p-5">
            <div className="flex items-start justify-between">
              <div>
                <h3 className="text-amber-50 font-bold text-lg">{plan.name}</h3>
                <code className="text-xs text-amber-600 bg-amber-950/30 px-2 py-0.5 rounded">{plan.code}</code>
                <p className="text-amber-400/50 text-sm mt-1">{plan.description}</p>
              </div>
              <button onClick={() => toggleActive(plan)} className={`p-2 rounded-lg transition-colors ${plan.is_active ? 'bg-green-900/30 text-green-400' : 'bg-red-900/30 text-red-400'}`}>
                {plan.is_active ? <Check size={16} /> : <X size={16} />}
              </button>
            </div>
            <div className="flex gap-6 mt-4 text-sm">
              <span className="text-amber-300/80">شهرياً: <strong className="text-amber-50">{plan.price_monthly} ريال</strong></span>
              <span className="text-amber-300/80">سنوياً: <strong className="text-amber-50">{plan.price_yearly || plan.price_monthly * 12} ريال</strong></span>
              <span className="text-amber-300/80">المستخدمون: <strong className="text-amber-50">{plan.max_users}</strong></span>
              <span className="text-amber-300/80">المشاريع: <strong className="text-amber-50">{plan.max_projects || 'غير محدود'}</strong></span>
            </div>
          </div>
        ))}
      </div>

      {showForm && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-4" onClick={() => setShowForm(false)}>
          <div className="bg-[#12101a] border border-[#2a1f0a] rounded-2xl p-6 w-full max-w-md" onClick={(e) => e.stopPropagation()}>
            <h2 className="text-lg font-bold text-amber-50 mb-4">إضافة خطة جديدة</h2>
            <div className="space-y-3">
              <input placeholder="الكود (مثال: premium)" value={form.code} onChange={(e) => setForm({...form, code: e.target.value})} className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 text-sm" />
              <input placeholder="اسم الخطة" value={form.name} onChange={(e) => setForm({...form, name: e.target.value})} className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 text-sm" />
              <input placeholder="الوصف" value={form.description} onChange={(e) => setForm({...form, description: e.target.value})} className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 text-sm" />
              <div className="grid grid-cols-2 gap-3">
                <input type="number" placeholder="السعر شهرياً" value={form.price_monthly} onChange={(e) => setForm({...form, price_monthly: Number(e.target.value)})} className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 text-sm" />
                <input type="number" placeholder="السعر سنوياً" value={form.price_yearly} onChange={(e) => setForm({...form, price_yearly: Number(e.target.value)})} className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 text-sm" />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <input type="number" placeholder="أقصى عدد مستخدمين" value={form.max_users} onChange={(e) => setForm({...form, max_users: Number(e.target.value)})} className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 text-sm" />
                <input type="number" placeholder="أقصى عدد مشاريع (0 = غير محدود)" value={form.max_projects} onChange={(e) => setForm({...form, max_projects: Number(e.target.value)})} className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 text-sm" />
              </div>
            </div>
            <div className="flex gap-3 mt-6">
              <button onClick={() => setShowForm(false)} className="flex-1 py-2.5 bg-[#1a1625] border border-[#2a1f0a] text-amber-300 rounded-xl text-sm">إلغاء</button>
              <button onClick={savePlan} disabled={saving || !form.name} className="flex-1 py-2.5 bg-amber-600 hover:bg-amber-500 disabled:bg-amber-800 text-white rounded-xl text-sm flex items-center justify-center gap-2">{saving && <Loader2 size={16} className="animate-spin" />}حفظ</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { Key, Plus, Loader2, Copy, Check } from 'lucide-react';

const ADMIN_TOKEN_KEY = 'zerocold_token';

interface ActivationCode {
  id: string; code: string; plan_code: string; duration_months: number;
  is_used: boolean; company_name: string; created_at: string;
}

export default function CodesPage() {
  const router = useRouter();
  const [codes, setCodes] = useState<ActivationCode[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [planCode, setPlanCode] = useState('monthly');
  const [duration, setDuration] = useState(12);
  const [generatedCode, setGeneratedCode] = useState('');
  const [copied, setCopied] = useState(false);
  const [saving, setSaving] = useState(false);

  const fetchCodes = async () => {
    const token = localStorage.getItem(ADMIN_TOKEN_KEY);
    if (!token) { router.replace('/zerocold/login'); return; }
    try {
      const res = await fetch('/api/admin/activation-codes', { headers: { Authorization: `Bearer ${token}` } });
      const body = await res.json();
      if (body.success) setCodes(body.data);
    } finally { setLoading(false); }
  };

  useEffect(() => { fetchCodes(); }, []);

  const generateCode = async () => {
    setSaving(true);
    const token = localStorage.getItem(ADMIN_TOKEN_KEY);
    try {
      const res = await fetch('/api/admin/activation-codes', {
        method: 'POST', headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ planCode, durationMonths: duration }),
      });
      const body = await res.json();
      if (body.success) { setGeneratedCode(body.data.code); fetchCodes(); }
    } finally { setSaving(false); }
  };

  const copyCode = () => {
    navigator.clipboard.writeText(generatedCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  if (loading) return <div className="flex items-center justify-center h-64"><Loader2 className="w-8 h-8 animate-spin text-amber-500" /></div>;

  return (
    <div className="p-6 max-w-5xl mx-auto" dir="rtl">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-xl font-bold text-amber-50">أكواد التفعيل</h1>
          <p className="text-amber-400/60 text-sm">توليد وإدارة أكواد تفعيل الاشتراكات</p>
        </div>
        <button onClick={() => { setShowForm(true); setGeneratedCode(''); }} className="px-4 py-2 bg-amber-600 hover:bg-amber-500 text-white rounded-xl text-sm flex items-center gap-2 transition-colors"><Plus size={16} />توليد كود</button>
      </div>

      {showForm && (
        <div className="bg-[#12101a] border border-[#2a1f0a] rounded-2xl p-5 mb-6">
          <h3 className="text-amber-50 font-bold mb-4">توليد كود تفعيل جديد</h3>
          <div className="flex gap-3 items-end">
            <div className="flex-1">
              <label className="block text-xs text-amber-400/60 mb-1">الخطة</label>
              <select value={planCode} onChange={(e) => setPlanCode(e.target.value)} className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 text-sm">
                <option value="trial">تجريبي</option>
                <option value="monthly">شهري</option>
                <option value="yearly">سنوي</option>
                <option value="starter">مبتدئ</option>
                <option value="professional">احترافي</option>
                <option value="enterprise">مؤسسات</option>
              </select>
            </div>
            <div className="w-32">
              <label className="block text-xs text-amber-400/60 mb-1">المدة (أشهر)</label>
              <input type="number" value={duration} onChange={(e) => setDuration(Number(e.target.value))} min={1} max={120} className="w-full px-4 py-2.5 bg-[#1a1625] border border-[#2a1f0a] rounded-xl text-amber-50 text-sm" />
            </div>
            <button onClick={generateCode} disabled={saving} className="px-6 py-2.5 bg-amber-600 hover:bg-amber-500 disabled:bg-amber-800 text-white rounded-xl text-sm flex items-center gap-2">{saving && <Loader2 size={16} className="animate-spin" />}توليد</button>
          </div>
          {generatedCode && (
            <div className="mt-4 p-3 bg-amber-950/30 border border-amber-700/30 rounded-xl flex items-center gap-3">
              <code className="flex-1 text-amber-300 text-sm font-mono">{generatedCode}</code>
              <button onClick={copyCode} className="p-2 hover:bg-amber-900/30 rounded-lg transition-colors">
                {copied ? <Check size={16} className="text-green-400" /> : <Copy size={16} className="text-amber-400" />}
              </button>
            </div>
          )}
        </div>
      )}

      <div className="space-y-2">
        {codes.map((c) => (
          <div key={c.id} className="flex items-center gap-3 bg-[#12101a] border border-[#2a1f0a] rounded-xl p-3">
            <Key size={16} className="text-amber-600 shrink-0" />
            <code className="flex-1 text-amber-300/80 text-sm font-mono">{c.code}</code>
            <span className="text-xs text-amber-400/60">{c.plan_code}</span>
            <span className="text-xs text-amber-400/60">{c.duration_months} أشهر</span>
            <span className={`text-xs px-2 py-0.5 rounded ${c.is_used ? 'bg-amber-900/30 text-amber-400' : 'bg-green-900/30 text-green-400'}`}>{c.is_used ? 'مستخدم' : 'جديد'}</span>
            {c.company_name && <span className="text-xs text-amber-400/60">{c.company_name}</span>}
          </div>
        ))}
        {codes.length === 0 && <p className="text-center text-amber-600 py-12">لا توجد أكواد تفعيل</p>}
      </div>
    </div>
  );
}

