    );
    const total = countRes.rows[0].total;

    params.push(pageSize, (page - 1) * pageSize);

    const res = await query(
      `SELECT u.id, u.name, u.email, u.role, u.is_active, u.last_login,
              u.created_at, u.company_id,
              c.name as company_name
       FROM users u
       JOIN companies c ON c.id = u.company_id
       ${whereClause}
       ORDER BY u.created_at DESC
       LIMIT $${paramIdx} OFFSET $${paramIdx + 1}`,
      params
    );

    return success({
      users: res.rows,
      total,
      page,
      pageSize,
    });
  } catch (err) {
    return serverError(err);
  }
}

import { NextRequest } from 'next/server';
import { success, error, unauthorized, serverError, notFound, parseBody } from '@/lib/api-helpers';
import { query, transaction } from '@/lib/db';
import { verifyPassword, verifyToken } from '@/lib/auth';

async function verifyAdmin(request: NextRequest) {
  const token = request.cookies.get('admin_token')?.value;
  if (!token) return null;
  const payload = verifyToken(token);
  if (!payload || payload.role !== 'superadmin') return null;
  return payload;
}

export async function PATCH(
  request: NextRequest,
  { params: paramsPromise }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await paramsPromise;
    const admin = await verifyAdmin(request);
    if (!admin) return unauthorized();

    const masterHeader = request.headers.get('x-master-password');
    if (!masterHeader) {
      return error('كلمة المرور الرئيسية مطلوبة في ترويسة x-master-password', 401);
    }

    const body = await parseBody<{ is_active: boolean }>(request);
    if (typeof body.is_active !== 'boolean') {
      return error('is_active يجب أن يكون true أو false');
    }

    const adminRes = await query(
      `SELECT master_password_hash FROM admin_users WHERE id = $1`,
      [admin.userId]
    );

    if (adminRes.rows.length === 0) {
      return error('المسؤول غير موجود', 401);
    }

    const masterHash = adminRes.rows[0].master_password_hash;
    const valid = await verifyPassword(masterHeader, masterHash);
    if (!valid) {
      return error('كلمة المرور الرئيسية غير صحيحة', 401);
    }

    const userRes = await query(
      `SELECT id, name, email, is_active FROM users WHERE id = $1`,
      [id]
    );

    if (userRes.rows.length === 0) {
      return notFound();
    }

    const user = userRes.rows[0];

    await transaction(async (client) => {
      await client.query(
        `UPDATE users SET is_active = $1, updated_at = NOW()::timestamp WHERE id = $2`,
        [body.is_active, id]
      );

      await client.query(
        `INSERT INTO admin_audit_log (admin_id, action, target_type, target_id, details)
         VALUES ($1, $2, 'user', $3, $4)`,
        [
          admin.userId,
          body.is_active ? 'activate_user' : 'deactivate_user',
          id,
          JSON.stringify({ userName: user.name, userEmail: user.email, previousState: user.is_active }),
        ]
      );
    });

    return success({
      message: body.is_active ? 'تم تفعيل المستخدم بنجاح' : 'تم إيقاف المستخدم بنجاح',
    });
  } catch (err) {
    return serverError(err);
  }
}

import { NextRequest } from 'next/server';
import { createHmac } from 'crypto';
import { query } from '@/lib/db';
import { success, error, serverError, parseBody } from '@/lib/api-helpers';

const SALT = process.env.PRO_ACCOUNTANT_LICENSE_SALT || 'default-salt-change-me';

export async function GET(req: NextRequest) {
  try {
    const used = req.nextUrl.searchParams.get('used');
    let sql = `SELECT a.*, c.name as company_name
               FROM activation_codes a
               LEFT JOIN companies c ON c.id = a.used_by`;
    const params: any[] = [];
    if (used === 'true') { sql += ' WHERE a.is_used = true'; }
    else if (used === 'false') { sql += ' WHERE a.is_used = false'; }
    sql += ' ORDER BY a.created_at DESC';
    const result = await query(sql, params);
    return success(result.rows);
  } catch (e: any) {
    return serverError(e);
  }
}

export async function POST(req: NextRequest) {
  try {
    const body = await parseBody(req);
    const { companyId, planCode, durationMonths } = body;
    if (!planCode || !durationMonths) return error('planCode and durationMonths required');

    const machineId = companyId || 'web-' + Date.now();
    const raw = `${planCode}-${machineId}-${durationMonths}`;
    const hmac = createHmac('sha256', SALT).update(raw).digest('hex').toUpperCase().slice(0, 16);
    const code = `${planCode}-${machineId.slice(0, 8)}-${durationMonths}-${hmac}`;

    const endDate = new Date();
    endDate.setMonth(endDate.getMonth() + durationMonths);

    await query(
      `INSERT INTO activation_codes (code, plan_code, duration_months, expires_at) VALUES ($1, $2, $3, $4)`,
      [code, planCode, durationMonths, endDate.toISOString().split('T')[0]]
    );

    return success({ code, planCode, durationMonths });
  } catch (e: any) {
    return serverError(e);
  }
}

import { NextRequest } from 'next/server';
import { query } from '@/lib/db';
import { success, error, serverError, parseBody } from '@/lib/api-helpers';

export async function GET(req: NextRequest) {
  try {
    const status = req.nextUrl.searchParams.get('status');
    let sql = `SELECT s.*, c.name as company_name, p.name as plan_name
               FROM subscriptions s
               LEFT JOIN companies c ON c.id = s.company_id
               LEFT JOIN subscription_plans p ON p.id = s.plan_id`;
    const params: any[] = [];
    if (status) {
      sql += ' WHERE s.status = $1';
      params.push(status);
    }
    sql += ' ORDER BY s.created_at DESC';
    const result = await query(sql, params);
    return success(result.rows);
  } catch (e: any) {
    return serverError(e);
  }
}

export async function POST(req: NextRequest) {
  try {
    const body = await parseBody(req);
    const { companyId, planCode, startDate, endDate, status, autoRenew } = body;
    if (!companyId || !planCode || !endDate) return error('companyId, planCode, endDate required');

    const result = await query(
      `INSERT INTO subscriptions (company_id, plan_code, status, start_date, end_date, auto_renew)
       VALUES ($1, $2, $3, $4, $5, $6)
       ON CONFLICT (company_id) DO UPDATE SET plan_code = $2, status = $3, end_date = $5, auto_renew = $6
       RETURNING *`,
      [companyId, planCode, status || 'active', startDate || new Date().toISOString().split('T')[0], endDate, autoRenew ?? true]
    );
    return success(result.rows[0]);
  } catch (e: any) {
    return serverError(e);
  }
}

import { NextRequest } from 'next/server';
import { query } from '@/lib/db';
import { success, error, serverError, parseBody } from '@/lib/api-helpers';

export async function GET(req: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  try {
    const { id } = await params;
    const result = await query(
      `SELECT s.*, c.name as company_name, p.name as plan_name, p.price_monthly
       FROM subscriptions s
       LEFT JOIN companies c ON c.id = s.company_id
       LEFT JOIN subscription_plans p ON p.id = s.plan_id
       WHERE s.id = $1`,
      [id]
    );
    if (result.rows.length === 0) return error('Not found', 404);
    const payments = await query(
      'SELECT * FROM payment_transactions WHERE subscription_id = $1 ORDER BY transaction_date DESC',
      [id]
    );
    return success({ ...result.rows[0], payments: payments.rows });
  } catch (e: any) {
    return serverError(e);
  }
}

export async function PUT(req: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  try {
    const { id } = await params;
    const body = await parseBody(req);
    const result = await query(
      `UPDATE subscriptions SET status = COALESCE($1, status), end_date = COALESCE($2, end_date),
       auto_renew = COALESCE($3, auto_renew) WHERE id = $4 RETURNING *`,
      [body.status, body.endDate, body.autoRenew, id]
    );
    if (result.rows.length === 0) return error('Not found', 404);
    return success(result.rows[0]);
  } catch (e: any) {
    return serverError(e);
  }
}
